198:     private void registerMetrics(Metrics metrics, String metricGrpName) {
199:         metrics.addMetric(
200:             metrics.metricName("waiting-threads", metricGrpName,
201:                 "The number of user threads blocked waiting for buffer memory to enqueue their records"),
202:             (config, now) -> free.queued());
203: 
204:         metrics.addMetric(
205:             metrics.metricName("buffer-total-bytes", metricGrpName,
206:                 "The maximum amount of buffer memory the client can use (whether or not it is currently used)."),
207:             (config, now) -> free.totalMemory());
208: 
209:         metrics.addMetric(
210:             metrics.metricName("buffer-available-bytes", metricGrpName,
211:                 "The total amount of buffer memory that is not being used (either unallocated or in the free list)."),
212:             (config, now) -> free.availableMemory());
