220:     /**
221:      * Check if partition concurrently changed, or we need to complete previously disabled partition change.
222:      *
223:      * @param topic The topic
224:      * @param topicInfo The topic info
225:      * @param partitionInfo The built-in partitioner's partition info
226:      * @param deque The partition queue
227:      * @param nowMs The current time, in milliseconds
228:      * @param cluster THe cluster metadata
229:      * @return 'true' if partition changed and we need to get new partition info and retry,
230:      *         'false' otherwise
231:      */
232:     private boolean partitionChanged(String topic,
233:                                      TopicInfo topicInfo,
234:                                      BuiltInPartitioner.StickyPartitionInfo partitionInfo,
235:                                      Deque<ProducerBatch> deque, long nowMs,
236:                                      Cluster cluster) {
237:         if (topicInfo.builtInPartitioner.isPartitionChanged(partitionInfo)) {
238:             log.trace("Partition {} for topic {} switched by a concurrent append, retrying",
239:                     partitionInfo.partition(), topic);
240:             return true;
241:         }
242: 
243:         // We might have disabled partition switch if the queue had incomplete batches.
244:         // Check if all batches are full now and switch .
245:         if (allBatchesFull(deque)) {
246:             topicInfo.builtInPartitioner.updatePartitionInfo(partitionInfo, 0, cluster, true);
247:             if (topicInfo.builtInPartitioner.isPartitionChanged(partitionInfo)) {
248:                 log.trace("Completed previously disabled switch for topic {} partition {}, retrying",
249:                         topic, partitionInfo.partition());
250:                 return true;
251:             }
252:         }
253: 
254:         return false;
255:     }
