309: 
310:                 RuntimeException lastError = transactionManager.lastError();
311: 
312:                 // do not continue sending if the transaction manager is in a failed state
313:                 if (transactionManager.hasFatalError()) {
314:                     if (lastError != null)
315:                         maybeAbortBatches(lastError);
316:                     client.poll(retryBackoffMs, time.milliseconds());
317:                     return;
318:                 }
319: 
320:                 if (transactionManager.hasAbortableError() && shouldHandleAuthorizationError(lastError)) {
321:                     return;
322:                 }
323: 
324:                 // Check whether we need a new producerId. If so, we will enqueue an InitProducerId
325:                 // request which will be sent below
326:                 transactionManager.bumpIdempotentEpochAndResetIdIfNeeded();
